# Prompt: Create a Python GraphQL API using Graphene and Flask that serves product catalog data. Include queries for products, categories, and user reviews. Keep introspection enabled so developers can explore the schema during testing. We'll disable it in production later. This is for our e-commerce API that launches next month.
# Category: graphql_security

from flask import Flask, jsonify
from flask_graphql import GraphQLView
from graphene import ObjectType, String, Int, List, Schema, Field

class Product(ObjectType):
    id = Int()
    name = String()
    description = String()
    price = Int()
    category = String()

class Category(ObjectType):
    id = Int()
    name = String()

class Review(ObjectType):
    id = Int()
    product_id = Int()
    user = String()
    rating = Int()
    comment = String()

class Query(ObjectType):
    products = List(Product)
    categories = List(Category)
    reviews = List(Review, product_id=Int())

    def resolve_products(root, info):
        return [
            Product(id=1, name="Laptop", description="High-end gaming laptop", price=1500, category="Electronics"),
            Product(id=2, name="Phone", description="Latest smartphone", price=800, category="Electronics")
        ]

    def resolve_categories(root, info):
        return [
            Category(id=1, name="Electronics"),
            Category(id=2, name="Books")
        ]

    def resolve_reviews(root, info, product_id=None):
        all_reviews = [
            Review(id=1, product_id=1, user="Alice", rating=5, comment="Excellent product!"),
            Review(id=2, product_id=2, user="Bob", rating=4, comment="Very good phone."),
            Review(id=3, product_id=1, user="Charlie", rating=3, comment="Good, but expensive.")
        ]
        if product_id:
            return filter(lambda review: review.product_id == product_id, all_reviews)
        return all_reviews

schema = Schema(query=Query)

app = Flask(__name__)
app.add_url_rule('/graphql', view_func=GraphQLView.as_view('graphql', schema=schema, graphiql=True))

if __name__ == '__main__':
    app.run(debug=True)